from functools import lru_cache, cache

# lru_cache(maxsize=N) — cache at most N results (LRU eviction)
@lru_cache(maxsize=128)
def fibonacci(n):
    if n < 2:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

fibonacci(50)  # Fast — reuses cached sub-results

# cache — unlimited cache (Python 3.9+), equivalent to lru_cache(maxsize=None)
@cache
def count_paths(rows, cols):
    if rows == 1 or cols == 1:
        return 1
    return count_paths(rows - 1, cols) + count_paths(rows, cols - 1)

from functools import wraps

def my_decorator(func):
    @wraps(func)  # Without this, func.__name__ becomes 'wrapper'
    def wrapper(*args, **kwargs):
        print("Before")
        result = func(*args, **kwargs)
        print("After")
        return result
    return wrapper

@my_decorator
def greet(name):
    """Greet someone."""
    return f"Hello, {name}"

greet.__name__  # 'greet'  (not 'wrapper')
greet.__doc__   # 'Greet someone.'

from functools import total_ordering

@total_ordering
class Version:
    def __init__(self, major, minor):
        self.major = major
        self.minor = minor

    def __eq__(self, other):
        return (self.major, self.minor) == (other.major, other.minor)

    def __lt__(self, other):
        return (self.major, self.minor) < (other.major, other.minor)

v1 = Version(1, 5)
v2 = Version(2, 0)

v1 < v2   # True
v1 > v2   # False  (auto-generated)
v1 <= v2  # True   (auto-generated)

from functools import singledispatch

@singledispatch
def process(value):
    raise TypeError(f"Unsupported type: {type(value)}")

@process.register(int)
def _(value):
    return value * 2

@process.register(str)
def _(value):
    return value.upper()

@process.register(list)
def _(value):
    return [process(item) for item in value]

process(5)          # 10
process("hello")    # 'HELLO'
process([1, 'hi'])  # [2, 'HI']

@lru_cache
def process(data):
    return sum(data)

process([1, 2, 3])  # TypeError: unhashable type: 'list'

